{"version":3,"file":"emotion-react.umd.min.js","sources":["../../sheet/src/index.ts","../../../node_modules/stylis/src/Enum.js","../../../node_modules/stylis/src/Utility.js","../../../node_modules/stylis/src/Tokenizer.js","../../../node_modules/stylis/src/Parser.js","../../../node_modules/stylis/src/Serializer.js","../../weak-memoize/src/index.ts","../../memoize/src/index.ts","../../cache/src/stylis-plugins.ts","../../cache/src/prefixer.ts","../../cache/src/index.ts","../../../node_modules/stylis/src/Middleware.js","../src/context.tsx","../../../node_modules/@babel/runtime/helpers/esm/extends.js","../../../node_modules/react-is/cjs/react-is.production.min.js","../../../node_modules/react-is/index.js","../../../node_modules/hoist-non-react-statics/dist/hoist-non-react-statics.cjs.js","../src/theming.tsx","../../utils/src/index.ts","../src/utils.ts","../../unitless/src/index.ts","../../serialize/src/conditions/false.ts","../../serialize/src/index.ts","../../hash/src/index.ts","../../use-insertion-effect-with-fallbacks/src/index.ts","../src/emotion-element.tsx","../src/jsx.ts","../src/global.tsx","../src/css.ts","../src/class-names.tsx","../src/keyframes.ts","../src/_isolated-hnrs.ts"],"sourcesContent":["import isDevelopment from '#is-development'\n/*\n\nBased off glamor's StyleSheet, thanks Sunil ❤️\n\nhigh performance StyleSheet for css-in-js systems\n\n- uses multiple style tags behind the scenes for millions of rules\n- uses `insertRule` for appending in production for *much* faster performance\n\n// usage\n\nimport { StyleSheet } from '@emotion/sheet'\n\nlet styleSheet = new StyleSheet({ key: '', container: document.head })\n\nstyleSheet.insert('#box { border: 1px solid red; }')\n- appends a css rule into the stylesheet\n\nstyleSheet.flush()\n- empties the stylesheet of all its contents\n\n*/\n\nfunction sheetForTag(tag: HTMLStyleElement): CSSStyleSheet {\n  if (tag.sheet) {\n    return tag.sheet\n  }\n\n  // this weirdness brought to you by firefox\n  /* istanbul ignore next */\n  for (let i = 0; i < document.styleSheets.length; i++) {\n    if (document.styleSheets[i].ownerNode === tag) {\n      return document.styleSheets[i]\n    }\n  }\n\n  // this function should always return with a value\n  // TS can't understand it though so we make it stop complaining here\n  return undefined as any\n}\n\nexport type Options = {\n  nonce?: string\n  key: string\n  container: Node\n  speedy?: boolean\n  prepend?: boolean\n  insertionPoint?: HTMLElement\n}\n\nfunction createStyleElement(options: Options): HTMLStyleElement {\n  let tag = document.createElement('style')\n  tag.setAttribute('data-emotion', options.key)\n  if (options.nonce !== undefined) {\n    tag.setAttribute('nonce', options.nonce)\n  }\n  tag.appendChild(document.createTextNode(''))\n  tag.setAttribute('data-s', '')\n  return tag\n}\n\nexport class StyleSheet {\n  isSpeedy: boolean\n  ctr: number\n  tags: HTMLStyleElement[]\n  // Using Node instead of HTMLElement since container may be a ShadowRoot\n  container: Node\n  key: string\n  nonce: string | undefined\n  prepend: boolean | undefined\n  before: Element | null\n  insertionPoint: HTMLElement | undefined\n\n  private _alreadyInsertedOrderInsensitiveRule: boolean | undefined\n\n  constructor(options: Options) {\n    this.isSpeedy =\n      options.speedy === undefined ? !isDevelopment : options.speedy\n    this.tags = []\n    this.ctr = 0\n    this.nonce = options.nonce\n    // k